/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements NotificationAdapter interface per the event-driven notification
 * architecture. Registered with NotificationService at startup.
 *
 * Features:
 * - JSON payload formatting: serializes NotificationPayload for webhook consumers
 * - URL validation: checks recipient is a valid HTTP/HTTPS URL before sending
 * - Configurable transport: supports pluggable post function for testing/production
 * - Error handling: never throws, returns failed NotificationResult on errors
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to webhook endpoints.
 */
export interface WebhookPayloadBody {
  notificationId: string;
  type: string;
  subject: string;
  body: string;
  recipient: string;
  priority: string;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

/**
 * Represents a webhook delivery attempt for inspection/testing.
 */
export interface WebhookDelivery {
  url: string;
  payload: WebhookPayloadBody;
  sentAt: Date;
}

/**
 * Configuration for the WebhookAdapter.
 */
export interface WebhookAdapterConfig {
  /** Timeout in milliseconds for webhook requests (default: 5000) */
  timeoutMs: number;
  /** Custom post function — defaults to in-memory logging */
  postFn?: (url: string, body: WebhookPayloadBody) => Promise<void>;
}

const DEFAULT_CONFIG: WebhookAdapterConfig = {
  timeoutMs: 5000,
};

/**
 * Validates that a string is an HTTP or HTTPS URL.
 */
function isValidWebhookUrl(url: string): boolean {
  const trimmed = url.trim();
  if (!trimmed) return false;
  try {
    const parsed = new URL(trimmed);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private config: WebhookAdapterConfig;

  constructor(config?: Partial<WebhookAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Validate the webhook URL.
   * Returns the trimmed URL or null if invalid.
   */
  validateUrl(url: string): string | null {
    const trimmed = url.trim();
    if (!isValidWebhookUrl(trimmed)) {
      this.logger.warn(`Invalid webhook URL: ${url}`);
      return null;
    }
    return trimmed;
  }

  /**
   * Format a notification payload into the JSON body sent to webhook endpoints.
   */
  formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      notificationId: payload.id,
      type: payload.type,
      subject: payload.subject,
      body: payload.body,
      recipient: payload.recipient,
      priority: payload.priority,
      createdAt: payload.createdAt.toISOString(),
      metadata: payload.metadata,
    };
  }

  /**
   * Send a notification through the webhook channel.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate URL
      const validatedUrl = this.validateUrl(payload.recipient);
      if (!validatedUrl) {
        return {
          success: false,
          notificationId: payload.id,
          channel: 'webhook',
          error: `Invalid webhook URL: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      // Format payload
      const webhookBody = this.formatPayload(payload);

      // Post via transport
      if (this.config.postFn) {
        await this.config.postFn(validatedUrl, webhookBody);
      }

      const delivery: WebhookDelivery = {
        url: validatedUrl,
        payload: webhookBody,
        sentAt: new Date(),
      };

      this.deliveries.push(delivery);
      this.logger.info(`Webhook delivered to ${validatedUrl}: ${payload.subject}`);

      return {
        success: true,
        notificationId: payload.id,
        channel: 'webhook',
        deliveredAt: delivery.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to deliver webhook to ${payload.recipient}: ${errorMessage}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: 'webhook',
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all webhook deliveries. Useful for testing.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Clear deliveries. Useful for testing.
   */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'webhook',
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter();
  });

  describe('send', () => {
    it('should send a webhook successfully', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');
      expect(result.deliveredAt).toBeInstanceOf(Date);
    });

    it('should store deliveries for inspection', async () => {
      await adapter.send(makePayload());

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]?.payload.notificationId).toBe('notif-0001');
    });

    it('should accumulate multiple deliveries', async () => {
      await adapter.send(makePayload({ id: 'notif-0001' }));
      await adapter.send(makePayload({ id: 'notif-0002', recipient: 'https://other.example.com/hook' }));

      expect(adapter.getDeliveries()).toHaveLength(2);
    });

    it('should clear deliveries', async () => {
      await adapter.send(makePayload());
      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });
  });

  describe('URL validation', () => {
    it('should accept https URLs', async () => {
      const result = await adapter.send(makePayload({ recipient: 'https://hooks.example.com/notify' }));
      expect(result.success).toBe(true);
    });

    it('should accept http URLs', async () => {
      const result = await adapter.send(makePayload({ recipient: 'http://hooks.example.com/notify' }));
      expect(result.success).toBe(true);
    });

    it('should trim whitespace from URLs', async () => {
      await adapter.send(makePayload({ recipient: '  https://hooks.example.com/notify  ' }));

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
    });

    it('should reject non-URL strings', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-url' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should reject empty URLs', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should reject non-HTTP protocols', async () => {
      const result = await adapter.send(makePayload({ recipient: 'ftp://files.example.com/hook' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should validate URL via validateUrl method', () => {
      expect(adapter.validateUrl('https://hooks.example.com/notify')).toBe('https://hooks.example.com/notify');
    });

    it('should return null for invalid URL via validateUrl', () => {
      expect(adapter.validateUrl('invalid')).toBeNull();
    });
  });

  describe('payload formatting', () => {
    it('should format payload as JSON-friendly object', () => {
      const payload = makePayload();
      const formatted = adapter.formatPayload(payload);

      expect(formatted.notificationId).toBe('notif-0001');
      expect(formatted.type).toBe('order-confirmation');
      expect(formatted.subject).toBe('Order Confirmation: order-1');
      expect(formatted.body).toContain('Widget x2');
      expect(formatted.priority).toBe('normal');
      expect(formatted.createdAt).toBe('2026-01-01T00:00:00.000Z');
    });

    it('should include metadata when present', () => {
      const payload = makePayload({ metadata: { orderId: 'order-1', userId: 'user-1' } });
      const formatted = adapter.formatPayload(payload);

      expect(formatted.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
    });

    it('should omit metadata when not present', () => {
      const payload = makePayload();
      delete payload.metadata;
      const formatted = adapter.formatPayload(payload);

      expect(formatted.metadata).toBeUndefined();
    });

    it('should include all notification types', async () => {
      for (const type of ['order-confirmation', 'order-status-update', 'user-welcome', 'user-profile-update'] as const) {
        await adapter.send(makePayload({ type }));
      }

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(4);
      expect(deliveries.map(d => d.payload.type)).toEqual([
        'order-confirmation',
        'order-status-update',
        'user-welcome',
        'user-profile-update',
      ]);
    });
  });

  describe('custom transport', () => {
    it('should call custom postFn when provided', async () => {
      const posted: Array<{ url: string; body: unknown }> = [];
      const customAdapter = new WebhookAdapter({
        postFn: async (url, body) => { posted.push({ url, body }); },
      });

      await customAdapter.send(makePayload());

      expect(posted).toHaveLength(1);
      expect(posted[0]?.url).toBe('https://hooks.example.com/notify');
    });

    it('should return failure when postFn throws', async () => {
      const customAdapter = new WebhookAdapter({
        postFn: async () => { throw new Error('Connection refused'); },
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
      expect(customAdapter.getDeliveries()).toHaveLength(0);
    });

    it('should still store delivery when using default transport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getDeliveries()).toHaveLength(1);
    });
  });

  describe('channel property', () => {
    it('should report webhook as its channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });
});

